filtered_books = []
for b in books:
    try:
        cats = ast.literal_eval(b['categories'])
    except:
        cats = b['categories'] if isinstance(b['categories'], list) else []

    if 'Literature & Fiction' in cats and 'English' in b['details']:
        filtered_books.append(b)

print(f"Filtered books count: {len(filtered_books)}")

def normalize_id(id_str):
    import re
    return re.sub(r'\D', '', id_str)

matched_books = []
for b in filtered_books:
    b_id = normalize_id(b['book_id'])
    for r in reviews:
        r_id = normalize_id(r['purchase_id'])
        if b_id == r_id:
            matched_books.append(b['title'])
            break

print("Matched books:", matched_books)

